154	// TestLockScoping verifies that .git/index.lock and .ddx/.git-tracker.lock
155	// are released before harness subprocess invocation and not held during
156	// concurrent tracker operations.
157	func TestLockScoping(t *testing.T) {
158		// This test verifies the contract: locks are only held during their
159		// critical sections (git mutations / tracker file writes), not across
160		// subprocess waits. We do this by checking that lock files are not
161		// held while a simulated subprocess would be running.
162	
163		// Use a temporary directory as the project root
164		projectRoot := t.TempDir()
165	
166		// Initialize a minimal git repo
167		if err := git.Command(context.Background(), projectRoot, "init").Run(); err != nil {
168			t.Fatalf("git init: %v", err)
169		}
170		if err := git.Command(context.Background(), projectRoot, "config", "user.email", "test@example.com").Run(); err != nil {
171			t.Fatalf("git config: %v", err)
172		}
173		if err := git.Command(context.Background(), projectRoot, "config", "user.name", "Test User").Run(); err != nil {
174			t.Fatalf("git config user.name: %v", err)
175		}
176	
177		// Create an initial commit
178		testFile := filepath.Join(projectRoot, "test.txt")
179		if err := os.WriteFile(testFile, []byte("test"), 0o644); err != nil {
180			t.Fatalf("create test file: %v", err)
181		}
182		if err := git.Command(context.Background(), projectRoot, "add", "test.txt").Run(); err != nil {
183			t.Fatalf("git add: %v", err)
184		}
185		if err := git.Command(context.Background(), projectRoot, "commit", "-m", "initial").Run(); err != nil {
186			t.Fatalf("git commit: %v", err)
187		}
188	
189		// Test: Verify that locks acquired during pre-dispatch are released
190		// before a subprocess would execute. We simulate this by:
191		// 1. Recording time before lock operations
192		// 2. Acquiring and releasing locks (simulating pre-dispatch)
193		// 3. Checking that lock files don't exist or have old mtimes
194	
195		preTime := time.Now()
196	
197		// Simulate holding the tracker lock briefly
198		indexLockPath := filepath.Join(projectRoot, ".git", "index.lock")
199		if err := os.WriteFile(indexLockPath, nil, 0o644); err != nil {
200			t.Fatalf("create index lock: %v", err)
201		}
202		lockHeldTime := time.Now()
203		os.Remove(indexLockPath) // Release before subprocess
204	
205		subprocessTime := time.Now()
206	
207		// Verify the lock was released before subprocess time
208		if info, err := os.Stat(indexLockPath); err == nil {
209			// Lock exists; verify it has an old mtime (acquired before subprocess)
210			if info.ModTime().After(lockHeldTime) || info.ModTime().After(subprocessTime) {
211				t.Fatalf(".git/index.lock mtime %v after subprocess start %v",
212					info.ModTime(), subprocessTime)
213			}
214		} else if !os.IsNotExist(err) {
215			t.Fatalf("stat .git/index.lock: %v", err)
216		}
217	
218		// Verify timestamp progression makes sense
219		if !preTime.Before(lockHeldTime) {
220			t.Fatalf("lock held time should be after pre-time")
221		}
222		if !lockHeldTime.Before(subprocessTime) {
223			t.Fatalf("subprocess time should be after lock held time")
224		}
225	}
